        $base + ['title' => 'Viking Refrigerator Door Gasket Failure', 'slug' => 'viking-refrigerator-door-gasket-failure',
            'meta_title' => 'Viking Refrigerator Door Gasket Failure — Warm Compartment, Condensation',
